    tax
    ldy.w #Rgb555HighComponentNormalizeDenominator
    lda $10
    and.w #Rgb555HighComponentMask
    jsl C0915B_DivideUnsignedWordByY
    ldy $0E
    jsr.w GET_COLOUR_FADE_SLOPE
    ldx $02
