    asl A
    asl A
    clc
    adc $06
    sta $06
    ldy.w #LandingProfilePointerBankOffset
    lda [$06],Y
    tay
    lda [$06]
    sta $06
    sty $08
    lda $1C
    and.w #LowByteMask
    ldy.w #LandingProfileRowStride
    jsl C08FF7_ResolveIndexedPointerOffset
    clc
    adc $06
    sta $06
